/**
 * The subset Ubuntu Sans Regular font as raw TrueType bytes, ready to hand
 * to resvg via `font.fontBuffers`.
 *
 * @returns a fresh `Uint8Array` of the decoded TTF on each call
 *
 * @example
 *   const resvg = new Resvg(svg, { font: { fontBuffers: [fallbackFontBytes()] } });
 */
export function fallbackFontBytes(): Uint8Array {
  return new Uint8Array(Buffer.from(FALLBACK_FONT_BASE64, 'base64'));
}
